from flask import Flask, request, jsonify
import os

app = Flask(__name__)

@app.route('/')
def index():
    return app.send_static_file('index.html')

@app.route('/api/health')
def health():
    return jsonify({'status': 'ok'})

if __name__ == '__main__':
    app.run(host='127.0.0.1', port=5000, debug=True)

from fastapi import FastAPI, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel

app = FastAPI()
app.add_middleware(CORSMiddleware, allow_origins=['http://localhost:3000'])

class ItemCreate(BaseModel):
    name: str
    value: int

@app.get('/api/items')
async def list_items():
    return {'items': []}

@app.post('/api/items')
async def create_item(item: ItemCreate):
    return {'id': 1, **item.dict()}

# Run: uvicorn main:app --host 127.0.0.1 --port 8000

import json
from pathlib import Path

CONFIG_PATH = Path(__file__).parent / 'config.json'
DEFAULTS = {'api_key': '', 'max_retries': 3, 'timeout': 30}

def load_config():
    if CONFIG_PATH.exists():
        with open(CONFIG_PATH, 'r') as f:
            user_config = json.load(f)
        return {**DEFAULTS, **user_config}
    return DEFAULTS.copy()

def save_config(config):
    with open(CONFIG_PATH, 'w') as f:
        json.dump(config, f, indent=2)

import threading

lock = threading.Lock()
shared_data = {}

def worker(task_id, params):
    try:
        result = process(params)
        with lock:
            shared_data[task_id] = {'status': 'done', 'result': result}
    except Exception as e:
        with lock:
            shared_data[task_id] = {'status': 'error', 'error': str(e)}

t = threading.Thread(target=worker, args=(task_id, params), daemon=True)
t.start()

import csv

def load_csv(filepath):
    with open(filepath, 'r', encoding='utf-8') as f:
        return list(csv.DictReader(f))

# Access by column name:
for row in load_csv('data.csv'):
    print(row['Name'], row['Category'])
